def evaluate_thought(client, problem: str, thought: str, model: str) -> int:
    """Evaluate a reasoning approach. Returns 0 on parse failure."""
    prompt = (f"Problem: {problem}\nApproach: {thought}\n"
              f"Score 1-10 for relevance and soundness. "
              f'Return JSON: {{"score": N, "reason": "..."}}')
    resp = client.chat.completions.create(
        model=model,
        messages=[{"role": "user", "content": prompt}],
        response_format={"type": "json_object"},
    )
    import json
    try:
        return json.loads(resp.choices[0].message.content).get("score", 0)
    except (json.JSONDecodeError, KeyError):
        return 0  # graceful degradation, not crash
